import { filterLlmsPublicObjects } from "./llms-filter.js";
import { createLlmsOutputId, extractLlmsEntities, isLlmsPublicObject, dedupeLlmsValues } from "./llms-utils.js";
import { formatLlmsLink, formatLlmsList } from "./llms-formatters.js";
import { validateLlmsOutput } from "./validate-llms-output.js";
import * as codes from "../validation/validation-codes.js";
/**
 * Generates compact llms.txt context index.
 */
export function generateLlmsTxt(input) {
    const diagnostics = [];
    // Check header
    if (!input.siteName || input.siteName.trim() === "") {
        diagnostics.push({
            id: `${codes.GC_LLMS_SITE_NAME_MISSING}_gen`,
            severity: "error",
            code: codes.GC_LLMS_SITE_NAME_MISSING,
            message: "Site name is missing.",
            field: "siteName",
        });
    }
    // Record excluded private objects
    for (const obj of input.objects) {
        if (!isLlmsPublicObject(obj)) {
            diagnostics.push({
                id: `${codes.GC_LLMS_PRIVATE_OBJECT_EXCLUDED}_${obj.id}`,
                severity: "info",
                code: codes.GC_LLMS_PRIVATE_OBJECT_EXCLUDED,
                message: `Excluded non-public object: ${obj.id}`,
                objectId: obj.id,
            });
        }
    }
    const publicObjects = filterLlmsPublicObjects(input);
    if (publicObjects.length === 0) {
        diagnostics.push({
            id: `${codes.GC_LLMS_NO_PUBLIC_OBJECTS}_gen`,
            severity: "warning",
            code: codes.GC_LLMS_NO_PUBLIC_OBJECTS,
            message: "No public objects matching visibility and language criteria are present.",
        });
    }
    const lines = [];
    lines.push(`# ${input.siteName}`);
    lines.push("");
    if (input.siteDescription) {
        lines.push(input.siteDescription);
        lines.push("");
    }
    if (input.siteUrl) {
        lines.push(`Website: ${input.siteUrl}`);
        lines.push("");
    }
    lines.push("## Knowledge Index");
    lines.push("");
    for (const obj of publicObjects) {
        const meta = input.metadata?.[obj.id];
        const url = meta?.canonicalUrl || meta?.seo?.canonicalUrl || obj.canonicalUrl;
        if (!url) {
            diagnostics.push({
                id: `${codes.GC_LLMS_CANONICAL_URL_MISSING}_${obj.id}`,
                severity: "warning",
                code: codes.GC_LLMS_CANONICAL_URL_MISSING,
                message: `Object lacks a canonical URL: ${obj.id}`,
                objectId: obj.id,
            });
        }
        const linkStr = formatLlmsLink(obj.title, url);
        const summaryStr = meta?.summary || obj.summary;
        lines.push(`- ${linkStr} — ${summaryStr}`);
    }
    lines.push("");
    // Extract important entities
    const allEntities = [];
    for (const obj of publicObjects) {
        const entities = extractLlmsEntities(obj, input.metadata?.[obj.id], input.relationships);
        allEntities.push(...entities);
    }
    const dedupedEntities = dedupeLlmsValues(allEntities);
    if (dedupedEntities.length > 0) {
        lines.push("## Important Entities");
        lines.push("");
        lines.push(formatLlmsList(dedupedEntities));
        lines.push("");
    }
    lines.push("## Trust & Freshness");
    lines.push("");
    lines.push("Generated by GeoCore.");
    const generatedAt = new Date().toISOString();
    lines.push(`Generated at: ${generatedAt}`);
    const content = lines.join("\n").trim();
    const id = createLlmsOutputId("llms.txt", input.siteName, input.language);
    const output = {
        id,
        type: "llms.txt",
        siteName: input.siteName,
        language: input.language,
        content,
        sourceObjectIds: publicObjects.map((o) => o.id),
        generatedAt,
        diagnostics,
    };
    const validation = validateLlmsOutput(output);
    if (!validation.valid || validation.issues.length > 0) {
        for (const issue of validation.issues) {
            const exists = diagnostics.some((d) => d.code === issue.code && d.objectId === issue.objectId);
            if (!exists) {
                diagnostics.push({
                    id: issue.id,
                    severity: issue.severity,
                    code: issue.code,
                    message: issue.message,
                    objectId: issue.objectId,
                    field: issue.field,
                    recommendation: issue.recommendation,
                });
            }
        }
    }
    return output;
}
